            // 2. Select item2. ToStringFunc returns "ITEM2" (not null).
            // Should use ToStringFunc and NOT RenderFragment.
            await comp.InvokeAsync(() => select!.SelectOption("item2"));
            comp.Render();

            displaySlots = comp.FindAll("div.mud-input-slot");
